$pageTitle='Ops Scheduler';$pageDescription='Stonefellow scheduled jobs, run history, queue dispatch, lifecycle scans, support SLA checks, revenue snapshots, and engagement refresh.';$pageClass='membership-page admin-catalog-page';
require __DIR__.'/../includes/admin_catalog.php';require_once __DIR__.'/../includes/ops_scheduler_messaging.php';sf_sec_require('admin.ops.manage');
if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){
 $action=(string)($_POST['action']??'');
 if($action==='save_job'){$id=sf_sched_save_job($_POST,(int)($_POST['job_id']??0));sf_admin_flash($id?'success':'error',$id?'Scheduled job saved.':'Job was rejected. Confirm its key, title, frequency, time, and status.');sf_admin_redirect($id?sf_url('admin/ops-scheduler.php?job_id='.$id):null);}
 if($action==='run_job'){$job=sf_sched_fetch_one('SELECT * FROM ops_scheduled_jobs WHERE id=? LIMIT 1',[(int)($_POST['job_id']??0)]);$r=$job?sf_sched_run_job($job,true):['ok'=>false,'summary'=>'Job not found.'];sf_admin_flash(!empty($r['ok'])?'success':'error',$r['summary']??'Job completed.');}
 if($action==='run_due'){$r=sf_sched_run_due(20);sf_admin_flash((int)$r['failed']>0?'warning':'success','Due jobs: '.(int)$r['success'].' successful, '.(int)$r['failed'].' failed, '.(int)$r['processed'].' processed.');}
 sf_admin_redirect(sf_url('admin/ops-scheduler.php'));
}
require __DIR__.'/../includes/header.php';$summary=sf_sched_summary();$jobs=sf_sched_jobs();$runs=sf_sched_runs(120);$editId=(int)($_GET['job_id']??($jobs[0]['id']??0));$editing=$editId?sf_sched_fetch_one('SELECT * FROM ops_scheduled_jobs WHERE id=? LIMIT 1',[$editId]):null;
sf_admin_shell_start('Ops Scheduler','Scheduled jobs v1','Run bounded, lease-protected operational jobs without overlapping executions.','ops-scheduler');
