<section class="sf-admin-two-col sf-admin-two-col-wide"><article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Job Registry</span><h2><?= count($jobs) ?> jobs</h2></div></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Job</th><th>Type</th><th>Frequency</th><th>Status</th><th>Next</th><th>Run</th></tr></thead><tbody><?php foreach($jobs as $j): ?><tr><td><strong><a href="<?= sf_url('admin/ops-scheduler.php?job_id='.(int)$j['id']) ?>"><?= sf_admin_h($j['title']) ?></a></strong><small><?= sf_admin_h($j['job_key']) ?></small></td><td><?= sf_admin_h($j['job_type']) ?></td><td><?= sf_admin_h($j['frequency']) ?><small><?= sf_admin_h($j['schedule_time']??'') ?></small></td><td><?= sf_admin_status_badge($j['status']) ?></td><td><?= sf_admin_h($j['next_run_at']?:'Manual') ?></td><td><form method="post" onsubmit="return confirm('Run this job now under an exclusive lease?')"><?= sf_csrf_field() ?><input type="hidden" name="action" value="run_job"><input type="hidden" name="job_id" value="<?= (int)$j['id'] ?>"><button type="submit">Run</button></form></td></tr><?php endforeach; ?><?php if(!$jobs): ?><tr><td colspan="6">No scheduled jobs found. Run migration 017.</td></tr><?php endif; ?></tbody></table></div></article>
<aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow"><?= $editing?'Edit':'Create' ?></span><h2><?= $editing?sf_admin_h($editing['title']):'Scheduled Job' ?></h2></div></div><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="save_job"><input type="hidden" name="job_id" value="<?= (int)($editing['id']??0) ?>"><label>Job Key<input name="job_key" maxlength="120" required value="<?= sf_admin_h($editing['job_key']??'') ?>"></label><label>Title<input name="title" maxlength="190" required value="<?= sf_admin_h($editing['title']??'') ?>"></label><label>Description<textarea name="description" maxlength="5000" rows="3"><?= sf_admin_h($editing['description']??'') ?></textarea></label><div class="sf-admin-form-grid"><label>Type<?= sf_admin_select('job_type',['dispatch_notifications'=>'Dispatch Notifications','lifecycle_churn_scan'=>'Lifecycle Churn Scan','support_sla_scan'=>'Support SLA Scan','revenue_snapshot'=>'Revenue Snapshot','engagement_score_refresh'=>'Engagement Score Refresh','custom'=>'Custom'],(string)($editing['job_type']??'custom')) ?></label><label>Frequency<?= sf_admin_select('frequency',['hourly'=>'Hourly','daily'=>'Daily','weekly'=>'Weekly','monthly'=>'Monthly','manual'=>'Manual'],(string)($editing['frequency']??'daily')) ?></label></div><div class="sf-admin-form-grid"><label>Schedule Time<input type="time" step="1" name="schedule_time" value="<?= sf_admin_h($editing['schedule_time']??'08:00:00') ?>"></label><label>Status<?= sf_admin_select('status',['active'=>'Active','paused'=>'Paused','archived'=>'Archived'],(string)($editing['status']??'paused')) ?></label></div><label>Next Run Override<input type="datetime-local" name="next_run_at" value="<?= !empty($editing['next_run_at'])?sf_admin_h(str_replace(' ','T',substr((string)$editing['next_run_at'],0,16))):'' ?>"></label><p class="sf-admin-copy">Manual jobs always store a null next-run time. Other jobs calculate the next future occurrence when no override is provided.</p><div class="sf-admin-form-actions"><button type="submit">Save Job</button></div></form></aside></section>
